// Parse Claude's JSON answer and re-validate it against the REQUEST the app sent.
// The app re-validates again (route + client), but rejecting garbage here keeps
// the failure visible in n8n executions. Contract: docs/n8n-plan-curation-workflow.md
const body = $('Webhook').item.json.body || {};
const menu = new Set((body.plants || []).map((p) => p.id));
const bounds = body.bounds || { min_picks: 1, max_picks: 12 };
const limits = body.limits || { intro_max_chars: 600, why_max_chars: 200 };

// The Anthropic node exposes the reply text on different fields depending on
// version — tolerate the common shapes.
const item = $input.first().json;
let text = item.text ?? item.content ?? item.message ?? '';
if (Array.isArray(text)) text = text[0]?.text ?? '';
if (typeof text === 'object' && text !== null) text = text.text ?? JSON.stringify(text);

function fail(message) {
  return [{ json: { branch: 'fallback', status: 'no_curation', message } }];
}

let parsed;
try {
  // Tolerate accidental markdown fences.
  const raw = String(text).trim().replace(/^```(json)?/i, '').replace(/```$/, '').trim();
  parsed = JSON.parse(raw);
} catch (e) {
  return fail('Claude answer was not valid JSON');
}

const intro = typeof parsed.intro === 'string' ? parsed.intro.trim() : '';
const selection = Array.isArray(parsed.selection) ? parsed.selection : null;
if (!intro || intro.length > limits.intro_max_chars) return fail('intro missing or too long');
if (!selection || selection.length < bounds.min_picks || selection.length > bounds.max_picks) {
  return fail('selection count outside bounds');
}
const seen = new Set();
const shaped = [];
for (const pick of selection) {
  const id = pick && typeof pick.plant_id === 'string' ? pick.plant_id : null;
  const why = pick && typeof pick.why === 'string' ? pick.why.trim() : '';
  if (!id || !menu.has(id) || seen.has(id)) return fail('selection contains an invalid or duplicate id');
  if (!why || why.length > limits.why_max_chars) return fail('a why line is missing or too long');
  seen.add(id);
  shaped.push({ plant_id: id, why });
}

return [{ json: { branch: 'ok', status: 'ok', intro, selection: shaped } }];
